33	// Properly typed component props based on react-markdown's actual types
34	type MarkdownComponentProps = React.HTMLAttributes<HTMLElement> & {
35	  node?: unknown;
36	  children?: React.ReactNode;
37	};
38	
39	// Code component specific props
40	interface CodeComponentProps extends MarkdownComponentProps {
41	  inline?: boolean;
42	}
43	
44	export const mdxComponents = {
45	  // Spread Fumadocs default components first (includes Next.js Image-optimized img)
46	  ...defaultMdxComponents,
47	
48	  // Custom overrides below
49	
50	  // Default img tag
51	  img({
52	    src,
53	    alt,
54	    className,
55	  }: MarkdownComponentProps & {
56	    src?: string;
57	    alt?: string;
58	  }) {
59	    if (!src) {
60	      return null;
61	    }
62	
63	    return (
64	      <Image
65	        alt={alt ?? ""}
66	        className={cn(
67	          "my-6 rounded-lg aspect-video",
68	          "h-auto w-full object-fill",
69	          className,
70	        )}
71	        height={0}
72	        sizes="100vw"
73	        src={src}
74	        width={0}
75	      />
76	    );
77	  },
78	
79	  // Code components - handles both inline and block code
80	  async code({ inline, className, children, ...props }: CodeComponentProps) {
81	    // Inline code styling
82	    if (inline) {
83	      return (
84	        <code
85	          className={cn(
86	            "rounded-md bg-muted/50 px-1 py-0.5 font-mono",
87	            className,
88	          )}
89	          {...props}
90	        >
91	          {children}
92	        </code>
93	      );
94	    }
95	
96	    // Block code - use SSRCodeBlock for syntax highlighting
97	    const langMatch = className?.match(/language-(\w+)/);
98	    if (langMatch && typeof children === "string") {
99	      const language = langMatch[1];
100	      return SSRCodeBlock({
101	        children,
102	        language,
103	        className: "my-6",
104	      });
105	    }
106	
107	    // Fallback: no language class (inline code that fumadocs doesn't mark with inline prop)
108	    return (
109	      <code
110	        className={cn(
111	          "rounded-md bg-muted/50 px-1 py-0.5 font-mono",
112	          className,
113	        )}
114	        {...props}
115	      >
116	        {children}
117	      </code>
118	    );
119	  },
120	
121	  // Pre component for code blocks - uses SSR syntax highlighting
122	  async pre({ children, className, ...props }: MarkdownComponentProps) {
123	    // Check if children is a code element with language class
124	    const child = Children.only(children);
125	    if (isValidElement(child) && child.type === "code") {
126	      const codeProps = child.props as {
127	        className?: string;
128	        children?: React.ReactNode;
129	      };
130	      const langMatch = codeProps.className?.match(/language-(\w+)/);
131	
132	      if (langMatch && typeof codeProps.children === "string") {
133	        const language = langMatch[1];
134	        const codeContent = codeProps.children;
135	
136	        // Call SSRCodeBlock as async function
137	        const highlighted = await SSRCodeBlock({
138	          children: codeContent,
139	          language,
140	          className: "my-6",
141	        });
142	        return highlighted;
143	      }
144	    }
145	
146	    // Fallback - just pass through children (SSRCodeBlock handles its own styling)
147	    return (
148	      <pre className={cn("my-6 text-sm", className)} {...props}>
149	        {children}
150	      </pre>
151	    );
152	  },
153	
154	  // Typography components
155	  strong({ children, ...props }: MarkdownComponentProps) {
156	    return (
157	      <strong className="font-semibold" {...props}>
158	        {children}
159	      </strong>
160	    );
161	  },
162	
163	  em({ children, ...props }: MarkdownComponentProps) {
164	    return (
165	      <em className="italic" {...props}>
166	        {children}
167	      </em>
168	    );
169	  },
170	
171	  // Link component - default <a> tag
172	  a({ href, children, ...props }: MarkdownComponentProps & { href?: string }) {
173	    const isExternal = href?.startsWith("http");
174	    return (
175	      <a
176	        className="text-inherit underline decoration-foreground/40 underline-offset-2 transition-colors hover:decoration-foreground"
177	        href={href}
178	        rel={isExternal ? "noopener noreferrer" : undefined}
179	        target={isExternal ? "_blank" : undefined}
180	        {...props}
181	      >
182	        {children}
183	      </a>
184	    );
185	  },
186	
187	  // Heading components with consistent styling
188	  h1({ children, ...props }: MarkdownComponentProps) {
189	    return (
190	      <h1
191	        className="mt-12 mb-6 scroll-m-20 font-bold text-3xl tracking-tight first:mt-0"
192	        {...props}
193	      >
194	        {children}
195	      </h1>
196	    );
197	  },
198	
199	  h2({ children, ...props }: MarkdownComponentProps) {
200	    return (
201	      <h2
202	        className="mt-12 scroll-m-20 font-semibold text-2xl font-pp"
203	        {...props}
204	      >
205	        {children}
206	      </h2>
207	    );
208	  },
209	
210	  h3({ children, ...props }: MarkdownComponentProps) {
211	    return (
212	      <h3
213	        className="mt-8 mb-4 scroll-m-20 font-semibold text-xl tracking-tight"
214	        {...props}
215	      >
216	        {children}
217	      </h3>
218	    );
219	  },
220	
221	  h4({ children, ...props }: MarkdownComponentProps) {
222	    return (
223	      <h4
224	        className="mt-6 mb-3 scroll-m-20 font-semibold text-lg tracking-tight"
225	        {...props}
226	      >
227	        {children}
228	      </h4>
229	    );
230	  },
231	
232	  h5({ children, ...props }: MarkdownComponentProps) {
233	    return (
234	      <h5
235	        className="mt-4 mb-2 scroll-m-20 font-semibold text-base tracking-tight"
236	        {...props}
237	      >
238	        {children}
239	      </h5>
240	    );
